<?php
/**
 * Service Worker PHP Wrapper (#81)
 *
 * This file is served as JavaScript but generated by PHP so that
 * the cache version is automatically derived from infoAppVer.php.
 * The .htaccess rule rewrites /service-worker.js → service-worker.js.php.
 *
 * Content-Type is set to JavaScript so the browser treats it correctly.
 */
header('Content-Type: application/javascript; charset=UTF-8');
header('Cache-Control: no-cache, no-store, must-revalidate');
header('Service-Worker-Allowed: /');

require_once __DIR__ . DIRECTORY_SEPARATOR . 'includes' . DIRECTORY_SEPARATOR . 'infoAppVer.php';
require_once __DIR__ . DIRECTORY_SEPARATOR . 'includes' . DIRECTORY_SEPARATOR . 'config.php';
$swVersion = $app['Application']['Version']['Number'] ?? '0.0.0';
$libs = APP_CONFIG['libraries'];

/* Collect CDN URLs for critical app shell resources */
$cdnAssets = array_filter([
    $libs['bootstrap']['css_cdn']   ?? null,
    $libs['bootstrap']['js_cdn']    ?? null,
    $libs['fontawesome']['css_cdn'] ?? null,
    $libs['jquery']['js_cdn']       ?? null,
    $libs['animatecss']['css_cdn']  ?? null,
]);

/* Collect local vendor fallback paths */
$vendorAssets = array_filter([
    $libs['bootstrap']['css_local']   ?? null,
    $libs['bootstrap']['js_local']    ?? null,
    $libs['fontawesome']['css_local'] ?? null,
    $libs['jquery']['js_local']       ?? null,
    $libs['animatecss']['css_local']  ?? null,
]);
?>
/**
 * iHymns — Service Worker
 *
 * Copyright (c) 2026 iHymns. All rights reserved.
 *
 * PURPOSE:
 * Provides offline support and caching for the iHymns PWA.
 *
 * STRATEGY:
 * "Network-first with offline fallback" — as per requirements:
 *   - Always try to load content from the host (network) first
 *   - Only fall back to cached content when the network is unreachable
 *   - Pre-caches essential app shell assets for instant offline access
 *   - Trusted CDN resources (Bootstrap, Font Awesome, jQuery, etc.) are
 *     cached for offline use — these CDNs serve CORS headers so SRI still works
 *
 * CACHE MANAGEMENT:
 *   - Cache version is derived from infoAppVer.php automatically
 *   - Old caches are automatically cleaned up on activation
 *
 * NOTE: This file is generated by PHP (service-worker.js.php) and served
 * via .htaccess rewrite as /service-worker.js. The PHP wrapper injects
 * the current app version into the CACHE_VERSION constant so it always
 * stays in sync with infoAppVer.php (#81).
 */

/* =========================================================================
 * CACHE CONFIGURATION
 * ========================================================================= */

/**
 * Cache version — derived from the application version in infoAppVer.php.
 * When the version is bumped by CI/CD, the service worker automatically
 * gets a new cache key, triggering a full cache purge on next load.
 */
const CACHE_VERSION = 'ihymns-v<?= $swVersion ?>';

/**
 * Songs cache (#105).
 * Separate bucket so it survives app version cache purges.
 * Stores recently viewed songs and bulk-downloaded songs for offline use.
 */
const RECENT_CACHE = 'ihymns-recent-songs';
const RECENT_CACHE_LIMIT = 2000;

/**
 * Assets to pre-cache during service worker installation.
 * These are the essential app shell files needed for offline access.
 */
const PRECACHE_ASSETS = [
    '/',
    '/css/app.css',
    '/css/accessibility.css',
    '/css/print.css',
    '/js/app.js',
    '/js/modules/router.js',
    '/js/modules/transitions.js',
    '/js/modules/settings.js',
    '/js/modules/search.js',
    '/js/modules/favorites.js',
    '/js/modules/pwa.js',
    '/js/modules/shuffle.js',
    '/js/modules/numpad.js',
    '/js/modules/share.js',
    '/js/modules/compare.js',
    '/js/modules/shortcuts.js',
    '/js/modules/request.js',
    '/js/modules/transpose.js',
    '/js/modules/reading-progress.js',
    '/js/modules/songbook-index.js',
    '/js/modules/search-history.js',
    '/js/modules/song-of-the-day.js',
    '/js/modules/offline-indicator.js',
    '/js/modules/storage-bridge.js',
    '/js/modules/subdomain-sync.js',
    '/manifest.json',
    '/assets/favicon.svg',
];

/**
 * Trusted CDN origins whose resources are cached for offline use.
 * These CDNs serve CORS headers (Access-Control-Allow-Origin: *)
 * so responses can be cached and later served with SRI verification.
 */
const TRUSTED_CDN_ORIGINS = [
    'https://cdn.jsdelivr.net',
    'https://cdnjs.cloudflare.com',
];

/**
 * Critical CDN assets to pre-cache during install for offline app shell.
 * Injected from config.php so CDN URLs stay in sync automatically.
 * These are fetched best-effort — CDN failures won't block installation.
 */
const PRECACHE_CDN_ASSETS = <?= json_encode(array_values($cdnAssets), JSON_UNESCAPED_SLASHES) ?>;

/**
 * Local vendor fallback paths — pre-cached best-effort.
 * These files are served when CDN resources are unavailable and the
 * CDN cache is also empty (e.g., first offline launch after install).
 */
const PRECACHE_VENDOR_ASSETS = <?= json_encode(
    array_map(fn($p) => '/' . $p, array_values($vendorAssets)),
    JSON_UNESCAPED_SLASHES
) ?>;

/**
 * Auto-update flag for offline songs (#132).
 * When true, the SW silently updates cached songs when changes are detected.
 * When false (default), the SW notifies the client and waits for confirmation.
 * Toggled via SET_AUTO_UPDATE message from the client.
 */
let autoUpdateOfflineSongs = false;

/**
 * In-flight navigation request map (#140).
 * Prevents duplicate fetches when rapid SPA navigation fires multiple
 * fetch events for the same URL concurrently. If a request for a URL
 * is already in-flight, subsequent requests share the same promise.
 * @type {Map<string, Promise<Response>>}
 */
const inflightNavigations = new Map();

/**
 * Send a message to all controlled clients.
 * @param {object} data Message payload
 */
async function notifyClients(data) {
    const clients = await self.clients.matchAll({ type: 'window' });
    clients.forEach(client => client.postMessage(data));
}

/* =========================================================================
 * INSTALL EVENT — Pre-cache essential assets
 * ========================================================================= */

self.addEventListener('install', (event) => {
    console.log('[SW] Installing service worker:', CACHE_VERSION);

    event.waitUntil(
        caches.open(CACHE_VERSION)
            .then(cache => {
                console.log('[SW] Pre-caching app shell assets');

                /* Local assets — must all succeed for install to complete */
                const localPromise = cache.addAll(PRECACHE_ASSETS);

                /*
                 * CDN assets — best effort. Failures are silently ignored so
                 * a CDN outage doesn't block service worker installation.
                 * These will be cached at runtime on the next page load anyway.
                 */
                const cdnPromise = Promise.allSettled(
                    PRECACHE_CDN_ASSETS.map(url =>
                        fetch(url, { mode: 'cors' })
                            .then(resp => {
                                if (resp.ok) return cache.put(url, resp);
                            })
                            .catch(() => console.warn('[SW] CDN precache skipped:', url))
                    )
                );

                /*
                 * Local vendor fallback files — best effort.
                 * These may not exist if the download-vendor script hasn't run.
                 */
                const vendorPromise = Promise.allSettled(
                    PRECACHE_VENDOR_ASSETS.map(path =>
                        fetch(path)
                            .then(resp => {
                                if (resp.ok) return cache.put(path, resp);
                            })
                            .catch(() => {})
                    )
                );

                return Promise.all([localPromise, cdnPromise, vendorPromise]);
            })
            .then(() => {
                /*
                 * Activate immediately so critical fixes (e.g., offline/CDN
                 * caching) take effect on the very next page load.
                 *
                 * Previously (#83) skipWaiting was omitted to let users control
                 * when updates activate via the "Refresh" notification. However,
                 * this caused the old SW (which doesn't cache CDN resources) to
                 * remain in control indefinitely, leaving offline support broken
                 * until the user happened to close every tab.
                 *
                 * The controllerchange listener in app.js will auto-reload the
                 * page when this new SW takes over, ensuring fresh HTML + cached
                 * CDN assets are served.
                 */
                console.log('[SW] Activating immediately via skipWaiting');
                return self.skipWaiting();
            })
    );
});

/* =========================================================================
 * ACTIVATE EVENT — Clean up old caches
 * ========================================================================= */

self.addEventListener('activate', (event) => {
    console.log('[SW] Activating service worker:', CACHE_VERSION);

    event.waitUntil(
        caches.keys()
            .then(cacheNames => {
                /* Delete any caches that don't match the current version */
                return Promise.all(
                    cacheNames
                        .filter(name => name !== CACHE_VERSION && name !== RECENT_CACHE)
                        .map(name => {
                            console.log('[SW] Deleting old cache:', name);
                            return caches.delete(name);
                        })
                );
            })
            .then(() => {
                /* Take control of all open tabs immediately */
                return self.clients.claim();
            })
    );
});

/* =========================================================================
 * FETCH EVENT — Network-first strategy with offline fallback
 *
 * Strategy per resource type:
 *   1. Trusted CDNs  → Network-first, cache for offline (Bootstrap, FA, jQuery)
 *   2. Other CDNs    → Network-only (analytics, third-party scripts)
 *   3. API requests  → Network-first, cache song pages for offline (#105)
 *   4. Local assets  → Network-first, cache on success, serve cache if offline
 *   5. Navigation    → Network-first, fall back to cached '/' for offline shell
 * ========================================================================= */

self.addEventListener('fetch', (event) => {
    const url = new URL(event.request.url);

    /* --- CDN / Third-party resources --- */
    if (url.origin !== self.location.origin) {
        /*
         * Trusted CDN resources (Bootstrap, Font Awesome, jQuery, etc.)
         * are cached with network-first strategy so the app shell renders
         * offline. These CDNs serve CORS headers, so cached responses
         * remain readable for SRI verification.
         */
        if (TRUSTED_CDN_ORIGINS.some(origin => url.origin === origin)) {
            event.respondWith(networkFirstWithCache(event.request));
            return;
        }
        /* Other third-party resources: let the browser handle normally */
        return;
    }

    /* --- API requests: network-first with cache for song pages (#105, #131) --- */
    if (url.pathname.startsWith('/api')) {
        const isSongPage = url.searchParams.get('page') === 'song';
        const songId = url.searchParams.get('id');
        event.respondWith(
            fetch(event.request)
                .then(async (response) => {
                    /* Cache song page API responses for offline access */
                    if (isSongPage && response.ok) {
                        const cache = await caches.open(RECENT_CACHE);
                        const existing = await cache.match(event.request);

                        if (existing) {
                            /* Compare content to detect updates (#131) */
                            const [newBody, oldBody] = await Promise.all([
                                response.clone().text(),
                                existing.text(),
                            ]);

                            if (newBody !== oldBody) {
                                if (autoUpdateOfflineSongs) {
                                    /* Auto-update: silently cache the new version */
                                    await cache.put(event.request, response.clone());
                                    notifyClients({
                                        type: 'SONG_UPDATED',
                                        songId,
                                        auto: true,
                                    });
                                } else {
                                    /* Manual mode: notify user, don't overwrite yet */
                                    notifyClients({
                                        type: 'SONG_UPDATE_AVAILABLE',
                                        songId,
                                        url: event.request.url,
                                    });
                                }
                            }
                            /* If content unchanged, refresh the cache timestamp */
                            else {
                                await cache.put(event.request, response.clone());
                            }
                        } else {
                            /* Not previously cached — just cache it */
                            await cache.put(event.request, response.clone());
                        }
                    }
                    return response;
                })
                .catch(() => {
                    /* Offline: try recently viewed cache for song pages */
                    if (isSongPage) {
                        return caches.match(event.request).then(cached => {
                            if (cached) return cached;
                            return new Response(
                                JSON.stringify({ error: 'You appear to be offline.' }),
                                { status: 503, headers: { 'Content-Type': 'application/json' } }
                            );
                        });
                    }
                    return new Response(
                        JSON.stringify({ error: 'You appear to be offline. Please check your connection.' }),
                        { status: 503, headers: { 'Content-Type': 'application/json' } }
                    );
                })
        );
        return;
    }

    /* --- Song data (served via API): network-first, cache for offline (#154) --- */
    if (url.pathname === '/api' && url.searchParams.get('action') === 'songs_json') {
        event.respondWith(networkFirstWithCache(event.request));
        return;
    }

    /* --- Navigation requests: network-first, offline shell fallback --- */
    /* Deduplicates concurrent fetches for the same URL (#140) */
    if (event.request.mode === 'navigate') {
        const navKey = url.pathname + url.search;
        const inflight = inflightNavigations.get(navKey);

        if (inflight) {
            /* Another fetch for this URL is already in-flight — share it */
            event.respondWith(inflight.then(r => r.clone()));
            return;
        }

        const navigationPromise = fetch(event.request)
            .then(response => {
                /* Only cache successful (2xx) responses — never cache
                 * redirects (301/302) as that causes infinite redirect
                 * loops when served from cache (#140) */
                if (response.ok) {
                    const clone = response.clone();
                    caches.open(CACHE_VERSION).then(cache => {
                        cache.put(event.request, clone);
                    });
                }
                return response;
            })
            .catch(() => {
                /* Offline — serve cached version, app shell, or branded fallback */
                return caches.match(event.request)
                    .then(cached => cached || caches.match('/'))
                    .then(resp => resp || offlineFallbackResponse());
            })
            .finally(() => {
                inflightNavigations.delete(navKey);
            });

        inflightNavigations.set(navKey, navigationPromise);
        event.respondWith(navigationPromise.then(r => r.clone()));
        return;
    }

    /* --- All other local assets: network-first with cache fallback --- */
    event.respondWith(networkFirstWithCache(event.request));
});

/* =========================================================================
 * HELPER FUNCTIONS
 * ========================================================================= */

