/**
 * Return the offline fallback page as a Response.
 * @returns {Response}
 */
function offlineFallbackResponse() {
    return new Response(OFFLINE_FALLBACK_HTML, {
        status: 503,
        statusText: 'Service Unavailable',
        headers: { 'Content-Type': 'text/html; charset=UTF-8' }
    });
}

/**
 * Network-first caching strategy.
 * Tries the network first; on success, caches the response.
 * On failure (offline), serves from cache if available.
 *
 * @param {Request} request The fetch request
 * @returns {Promise<Response>} The response
 */
async function networkFirstWithCache(request) {
    try {
        /* Try network first */
        const networkResponse = await fetch(request);

        /* Cache the successful response */
        if (networkResponse.ok) {
            const cache = await caches.open(CACHE_VERSION);
            cache.put(request, networkResponse.clone());
        }

        return networkResponse;

    } catch (error) {
        /* Network failed — try cache */
        const cachedResponse = await caches.match(request);
        if (cachedResponse) {
            return cachedResponse;
        }

        /* Nothing in cache either — show the branded offline page */
        return offlineFallbackResponse();
    }
}

/* =========================================================================
 * MESSAGE EVENT — Handle SKIP_WAITING from the client (#83)
 *
 * When the user clicks the "Refresh" button in the update notification,
 * the client sends a { type: 'SKIP_WAITING' } message. This tells the
 * waiting service worker to activate immediately, replacing the old one.
 * The client then receives a 'controllerchange' event and reloads.
 * ========================================================================= */

self.addEventListener('message', (event) => {
    if (!event.data) return;

    if (event.data.type === 'SKIP_WAITING') {
        console.log('[SW] Received SKIP_WAITING — activating now');
        self.skipWaiting();
    }

    /* Download all songs for offline use */
    if (event.data.type === 'CACHE_ALL_SONGS' && Array.isArray(event.data.songIds)) {
        const songIds = event.data.songIds;
        const total = songIds.length;
        let completed = 0;
        let failed = 0;

        caches.open(RECENT_CACHE).then(async (cache) => {
            /* Process in batches of 5 to avoid overwhelming the server */
            const BATCH_SIZE = 5;
            for (let i = 0; i < songIds.length; i += BATCH_SIZE) {
                const batch = songIds.slice(i, i + BATCH_SIZE);
                const results = await Promise.allSettled(
                    batch.map(async (id) => {
                        const url = `/api?page=song&id=${encodeURIComponent(id)}`;
                        /* Skip if already cached */
                        const existing = await cache.match(url);
                        if (existing) { completed++; return; }
                        const response = await fetch(url);
                        if (response.ok) {
                            await cache.put(url, response);
                            completed++;
                        } else {
                            failed++;
                        }
                    })
                );

                /* Report progress back to client */
                const clients = await self.clients.matchAll();
                clients.forEach(client => {
                    client.postMessage({
                        type: 'CACHE_ALL_SONGS_PROGRESS',
                        completed,
                        failed,
                        total,
                    });
                });
            }

            /* Remove the LRU limit for bulk downloads — keep all songs */
        });
    }

    /* Set auto-update preference (#132) */
    if (event.data.type === 'SET_AUTO_UPDATE') {
        autoUpdateOfflineSongs = !!event.data.enabled;
        console.log('[SW] Auto-update offline songs:', autoUpdateOfflineSongs);
    }

    /* Accept a pending song update — cache the fresh version (#131) */
    if (event.data.type === 'UPDATE_SONG_CACHE' && event.data.url) {
        try {
            const cacheUrl = new URL(event.data.url, self.location.origin);
            if (cacheUrl.origin !== self.location.origin) return;
        } catch { return; }

        caches.open(RECENT_CACHE).then(async (cache) => {
            try {
                const response = await fetch(event.data.url);
                if (response.ok) {
                    await cache.put(event.data.url, response);
                    notifyClients({
                        type: 'SONG_UPDATED',
                        songId: event.data.songId,
                        auto: false,
                    });
                }
            } catch (error) {
                console.warn('[SW] Failed to update cached song:', error.message);
            }
        });
    }

    /* Proactively cache a recently viewed song page (#105) */
    if (event.data.type === 'CACHE_SONG' && event.data.url) {
        /* Validate URL origin to prevent cache poisoning */
        try {
            const cacheUrl = new URL(event.data.url, self.location.origin);
            if (cacheUrl.origin !== self.location.origin) return;
        } catch { return; }

        caches.open(RECENT_CACHE).then(async (cache) => {
            try {
                const response = await fetch(event.data.url);
                if (response.ok) {
                    await cache.put(event.data.url, response);
                    /* Evict oldest entries if over limit */
                    const keys = await cache.keys();
                    if (keys.length > RECENT_CACHE_LIMIT) {
                        const toDelete = keys.slice(0, keys.length - RECENT_CACHE_LIMIT);
                        await Promise.all(toDelete.map(k => cache.delete(k)));
                    }
                }
            } catch (error) {
                console.warn('[SW] Failed to cache song:', event.data.url, error.message);
            }
        });
    }
});
